package com.i2i.voltwise.home;
import jakarta.persistence.*; import java.math.BigDecimal; import java.time.Instant; import java.util.*;
@Entity @Table(name="homes") public class Home { @Id public UUID id; @Column(nullable=false) public String name; @Column(nullable=false) public String email; @Column(name="budget_limit",nullable=false) public BigDecimal budgetLimit; @Column(name="base_tariff",nullable=false) public BigDecimal baseTariff; @Column(name="penalty_multiplier",nullable=false) public BigDecimal penaltyMultiplier; @Column(name="created_at",nullable=false) public Instant createdAt; @OneToMany(mappedBy="home",cascade=CascadeType.ALL,orphanRemoval=true) public List<Appliance> appliances=new ArrayList<>(); protected Home(){} public Home(UUID id,String name,String email,BigDecimal budget,BigDecimal tariff,BigDecimal penalty){this.id=id;this.name=name;this.email=email;this.budgetLimit=budget;this.baseTariff=tariff;this.penaltyMultiplier=penalty;this.createdAt=Instant.now();} }
